  ( H_case_cond : True ),
  balanceOf_transition ENV idx STATE NextAddr (state (Amm.addr STATE) (Amm.BALANCE STATE) (Amm.allowance STATE) (Amm.balanceOf STATE) (Amm.reserve0 STATE) (Amm.reserve1 STATE) (Amm.token0 STATE) (Amm.token1 STATE) (Amm.totalSupply STATE)) (NextAddr)

.

Inductive balanceOf_ret (ENV : Env) (idx : address) (STATE : State) (NextAddr : address) : Z -> Prop :=
| balanceOf_case0_ret :
     balanceOf_conds ENV idx STATE NextAddr
  -> True
  -> balanceOf_ret ENV idx STATE NextAddr ((Amm.balanceOf STATE) idx)

.


Inductive allowance_conds (ENV : Env) (idx1 : address) (idx2 : address) (STATE : State) (NextAddr : address) : Prop :=
| allowance_condsC : forall
  ( H_iff0 : ((Callvalue ENV) = 0) )
  ( H_nextAddrCnstrnt_State : nextAddrConstraint NextAddr STATE )
  ( H_argConstraints_intBounds_idx1 : 0 <= idx1 <= UINT_MAX 160 )
  ( H_argConstraints_intBounds_idx2 : 0 <= idx2 <= UINT_MAX 160 )
  ( H_CallerBound : 0 <= Caller ENV <= UINT_MAX 160 )
  ( H_OriginBound : 0 <= Origin ENV <= UINT_MAX 160 )
  ( H_ThisBound : 0 <= This ENV <= UINT_MAX 160 )
  ( H_NextAddressBound : 0 <= NextAddr <= UINT_MAX 160 )
  ( H_This_lt_NextAddr : This ENV < NextAddr )
  ( H_Caller_lt_NextAddr : Caller ENV < NextAddr )
  ( H_Origin_lt_NextAddr : Origin ENV < NextAddr )
  ( H_no_self_call : (forall (p : address), addressIn STATE p -> Caller ENV <> p) )
  ( H_no_self_origin : (forall (p : address), addressIn STATE p -> Origin ENV <> p) )
  ( H_This_eq_addState : This ENV = addr STATE ),
  allowance_conds ENV idx1 idx2 STATE NextAddr

.

Inductive allowance_transition (ENV : Env) (idx1 : address) (idx2 : address) (STATE : State) (NextAddr : address) : State -> address -> Prop :=
| allowance_case0 : forall
  ( H_conds : allowance_conds ENV idx1 idx2 STATE NextAddr )
  ( H_case_cond : True ),
  allowance_transition ENV idx1 idx2 STATE NextAddr (state (Amm.addr STATE) (Amm.BALANCE STATE) (Amm.allowance STATE) (Amm.balanceOf STATE) (Amm.reserve0 STATE) (Amm.reserve1 STATE) (Amm.token0 STATE) (Amm.token1 STATE) (Amm.totalSupply STATE)) (NextAddr)

.

Inductive allowance_ret (ENV : Env) (idx1 : address) (idx2 : address) (STATE : State) (NextAddr : address) : Z -> Prop :=
| allowance_case0_ret :
     allowance_conds ENV idx1 idx2 STATE NextAddr
  -> True
  -> allowance_ret ENV idx1 idx2 STATE NextAddr (((Amm.allowance STATE) idx1) idx2)

.


Inductive Amm_transition (ENV : Env) (STATE : State) (NextAddr : address) (STATE' : State) (NextAddr' : address) : Prop :=
| swap0_Amm_transition : forall (amount1Out : Z) (to : address),
   swap0_transition ENV amount1Out to STATE NextAddr STATE' NextAddr'
-> Amm_transition ENV STATE NextAddr STATE' NextAddr'
| swap1_Amm_transition : forall (amount0Out : Z) (to : address),
   swap1_transition ENV amount0Out to STATE NextAddr STATE' NextAddr'
-> Amm_transition ENV STATE NextAddr STATE' NextAddr'
| mint_Amm_transition : forall (to : address),
   mint_transition ENV to STATE NextAddr STATE' NextAddr'
-> Amm_transition ENV STATE NextAddr STATE' NextAddr'
| burn_Amm_transition : forall (liquidity : Z) (to : address),
   burn_transition ENV liquidity to STATE NextAddr STATE' NextAddr'
-> Amm_transition ENV STATE NextAddr STATE' NextAddr'
| transfer_Amm_transition : forall (val : Z) (to : address),
   transfer_transition ENV val to STATE NextAddr STATE' NextAddr'
-> Amm_transition ENV STATE NextAddr STATE' NextAddr'
| transferFrom_Amm_transition : forall (src : address) (dst : address) (amount : Z),
   transferFrom_transition ENV src dst amount STATE NextAddr STATE' NextAddr'
-> Amm_transition ENV STATE NextAddr STATE' NextAddr'
| approve_Amm_transition : forall (spender : address) (amount : Z),
   approve_transition ENV spender amount STATE NextAddr STATE' NextAddr'
-> Amm_transition ENV STATE NextAddr STATE' NextAddr'
| totalSupply_Amm_transition :
   totalSupply_transition ENV STATE NextAddr STATE' NextAddr'
-> Amm_transition ENV STATE NextAddr STATE' NextAddr'
| balanceOf_Amm_transition : forall (idx : address),
   balanceOf_transition ENV idx STATE NextAddr STATE' NextAddr'
-> Amm_transition ENV STATE NextAddr STATE' NextAddr'
| allowance_Amm_transition : forall (idx1 : address) (idx2 : address),
   allowance_transition ENV idx1 idx2 STATE NextAddr STATE' NextAddr'
-> Amm_transition ENV STATE NextAddr STATE' NextAddr'
.

Inductive transition (ENV : Env) (STATE : State) (NextAddr : address) (STATE' : State) (NextAddr' : address) : Prop :=
| transition_Amm :
     Amm_transition ENV STATE NextAddr STATE' NextAddr'
  -> transition ENV STATE NextAddr STATE' NextAddr'

| transition_token0 :
     nextAddrConstraint NextAddr STATE
  -> (forall (p : address), addressIn STATE p -> Origin ENV <> p)
  -> (forall (p : address), addressIn STATE p -> Caller ENV <> p)
  -> stateIntegerBounds STATE
  -> Token.transition ENV (token0 STATE) NextAddr (token0 STATE') NextAddr'
  -> addr STATE = addr STATE'
  -> (BALANCE STATE) = (BALANCE STATE')
  -> (allowance STATE) = (allowance STATE')
  -> (balanceOf STATE) = (balanceOf STATE')
  -> (reserve0 STATE) = (reserve0 STATE')
  -> (reserve1 STATE) = (reserve1 STATE')
  -> (token1 STATE) = (token1 STATE')
  -> (totalSupply STATE) = (totalSupply STATE')
  -> transition ENV STATE NextAddr STATE' NextAddr'

| transition_token1 :
     nextAddrConstraint NextAddr STATE
  -> (forall (p : address), addressIn STATE p -> Origin ENV <> p)
  -> (forall (p : address), addressIn STATE p -> Caller ENV <> p)
  -> stateIntegerBounds STATE
  -> Token.transition ENV (token1 STATE) NextAddr (token1 STATE') NextAddr'
  -> addr STATE = addr STATE'
  -> (BALANCE STATE) = (BALANCE STATE')
  -> (allowance STATE) = (allowance STATE')
  -> (balanceOf STATE) = (balanceOf STATE')
  -> (reserve0 STATE) = (reserve0 STATE')
  -> (reserve1 STATE) = (reserve1 STATE')
  -> (token0 STATE) = (token0 STATE')
  -> (totalSupply STATE) = (totalSupply STATE')
  -> transition ENV STATE NextAddr STATE' NextAddr'

.

Definition step (STATE : State) (STATE' : State) :=
exists (ENV : Env) (NextAddr : address) (NextAddr' : address), transition ENV STATE NextAddr STATE' NextAddr'.

Definition multistep (STATE STATE' : State) :=
multistep step STATE STATE'.

Definition reachable (STATE : State) :=
exists STATE', init STATE' /\ multistep STATE' STATE.

Definition reachableFromInit (ENV : Env) (t0 : Token.State) (t1 : Token.State) (liquidity : Z) (NextAddr : address) (STATE : State) :=
exists STATE' NextAddr', constructor ENV t0 t1 liquidity NextAddr STATE' NextAddr' /\ multistep STATE' STATE.

Definition stepBefore (BOUND : address) (STATE : State) (STATE' : State) :=
exists (ENV : Env) (NextAddr : address) (NextAddr' : address), transition ENV STATE NextAddr STATE' NextAddr' /\ NextAddr' <= BOUND.

Definition multistepBefore (BOUND : address) (STATE : State) (STATE' : State) :=
ActLib.multistep (stepBefore BOUND) STATE STATE'.

Definition reachableBefore (BOUND : address) (STATE : State) :=
exists STATE', initBefore BOUND STATE' /\ multistepBefore BOUND STATE' STATE.

Definition invariantInit (IP : Env -> Token.State -> Token.State -> Z -> address -> State -> Prop) :=
  forall (ENV : Env) (t0 : Token.State) (t1 : Token.State) (liquidity : Z) (NextAddr : address) (STATE : State) (NextAddr' : address),
     constructor ENV t0 t1 liquidity NextAddr STATE NextAddr'
  -> IP ENV t0 t1 liquidity NextAddr STATE
.

Definition invariantStep (IP : Env -> Token.State -> Token.State -> Z -> address -> State -> Prop) :=
  forall (ENV : Env) (t0 : Token.State) (t1 : Token.State) (liquidity : Z) (NextAddr : address) (STATE : State) (STATE' : State),
     constructor_conds ENV t0 t1 liquidity NextAddr
  -> step STATE STATE'
  -> IP ENV t0 t1 liquidity NextAddr STATE
  -> IP ENV t0 t1 liquidity NextAddr STATE'
.

Lemma invariantReachable :
  forall (ENV : Env) (t0 : Token.State) (t1 : Token.State) (liquidity : Z) (NextAddr : address) (STATE : State) (IP : Env -> Token.State -> Token.State -> Z -> address -> State -> Prop) (HIPinvInit : invariantInit IP) (HIPinvStep : invariantStep IP),
     reachableFromInit ENV t0 t1 liquidity NextAddr (STATE : State)
  -> IP ENV t0 t1 liquidity NextAddr STATE
.
Proof.
  intros ENV t0 t1 liquidity NextAddr STATE IP HIPinvInit HIPinvStep Hreach.
  unfold reachableFromInit in Hreach.
  destruct Hreach as [iState [iNA [Hinit Hmulti]]].
  apply step_multi_step with (P := fun s s' => IP ENV t0 t1 liquidity NextAddr s -> IP ENV t0 t1 liquidity NextAddr s' ) in Hmulti.
  - apply Hmulti.
    eapply HIPinvInit; eassumption.
  - intros s s' Hstep.
    destruct Hinit as [iNA' Hprecs].
    eapply HIPinvStep with (STATE := s) (STATE' := s'); eassumption.
  - unfold Relation_Definitions.reflexive.
    intros.
    assumption.
  - unfold Relation_Definitions.transitive.
    intros s1 s2 s3 Ht1 Ht2 Ht3.
    apply Ht2, Ht1.
    assumption.

Qed.


End Amm.
